script:
frappe.ui.form.on("Item", {
	setup(frm) {
		if (frm.fields_dict.default_location) {
			frm.set_query("default_location", () => {
				const filters = { enabled: 1 };
				if (frm.doc.supply_warehouse) {
					filters.warehouse = frm.doc.supply_warehouse;
				}
				return { filters };
			});
		}
	},

	refresh(frm) {
		syncItemUsageDefaults(frm, false);
	},

	item_usage_type(frm) {
		syncItemUsageDefaults(frm, true);
	},

	supply_warehouse(frm) {
		if (!frm.doc.default_location) {
			return;
		}

		frappe.db.get_value("Warehouse Location", frm.doc.default_location, "warehouse").then((response) => {
			const row = response.message || {};
			if (row.warehouse && frm.doc.supply_warehouse && row.warehouse !== frm.doc.supply_warehouse) {
				frm.set_value("default_location", "");
			}
		});
	}
});

function syncItemUsageDefaults(frm, updateFields) {
	const usage = frm.doc.item_usage_type;
	if (!usage) {
		return;
	}

	if (updateFields) {
		if (usage === "成品") {
			frm.set_value("sellable", 1);
			frm.set_value("supply_mode", "不适用");
			frm.set_value("is_fulfillment_consumable", 0);
		} else {
			frm.set_value("sellable", 0);
			if (!frm.doc.supply_mode || frm.doc.supply_mode === "不适用") {
				frm.set_value("supply_mode", "自供");
			}
			frm.set_value("is_fulfillment_consumable", usage === "包装耗材" ? 1 : 0);
		}
		if (["面料", "辅料", "包装耗材"].includes(usage) && frm.doc.is_stock_item !== 1) {
			frm.set_value("is_stock_item", 1);
		}
	}
}

frappe.ui.form.on("Sales Order", {
	channel_store(frm) {
		if (!frm.doc.channel_store) {
			return;
		}

		frappe.db.get_value("Channel Store", frm.doc.channel_store, "channel").then((response) => {
			const row = response.message || {};
			if (row.channel) {
				frm.set_value("channel", row.channel);
			}
		});
	}
});

frappe.ui.form.on("Sales Order", {
	refresh(frm) {
		addSalesOrderFulfillmentButtons(frm);
	}
});

function addSalesOrderFulfillmentButtons(frm) {
	if (frm.is_new() || frm.doc.docstatus === 2) {
		return;
	}

	const closedStatuses = ["已完成", "已关闭", "已取消"];
	if (closedStatuses.includes(frm.doc.fulfillment_status)) {
		return;
	}

	const items = frm.doc.items || [];
	if (hasFulfillmentRows(items, ["待处理"])) {
		addFulfillmentButton(frm, "配货", "fashion_erp.fashion_stock.services.sales_order_fulfillment_service.allocate_sales_order");
	}
	if (hasFulfillmentRows(items, ["待处理", "已锁库存", "拣货中"])) {
		addFulfillmentButton(frm, "拣货", "fashion_erp.fashion_stock.services.sales_order_fulfillment_service.pick_sales_order");
	}
	if (hasFulfillmentRows(items, ["已拣货", "打包中"])) {
		addFulfillmentButton(frm, "打包", "fashion_erp.fashion_stock.services.sales_order_fulfillment_service.pack_sales_order");
	}
	if (hasFulfillmentRows(items, ["待发货", "部分发货"])) {
		addFulfillmentButton(frm, "生成发货单", "fashion_erp.fashion_stock.services.sales_order_fulfillment_service.prepare_sales_order_delivery_note", {
			onSuccess(payload) {
				if (payload.delivery_note) {
					frappe.set_route("Form", "Delivery Note", payload.delivery_note);
				}
			}
		});
	}
}

function addFulfillmentButton(frm, label, method, options) {
	frm.add_custom_button(label, () => runFulfillmentAction(frm, label, method, options), __("履约"));
}

function runFulfillmentAction(frm, label, method, options) {
	const settings = options || {};
	frappe.call({
		method,
		args: {
			order_name: frm.doc.name
		},
		freeze: true,
		freeze_message: __("{0}处理中...", [label])
	}).then((response) => {
		const payload = response.message || {};
		if (payload.message) {
			frappe.show_alert({ message: payload.message, indicator: payload.ok === false ? "orange" : "green" }, 5);
		}
		const afterReload = () => {
			if (typeof settings.onSuccess === "function") {
				settings.onSuccess(payload);
			}
		};
		frm.reload_doc().then(afterReload);
	});
}

function hasFulfillmentRows(items, statuses) {
	return (items || []).some((row) => {
		if (!statuses.includes(row.fulfillment_status)) {
			return false;
		}
		return getPendingQty(row) > 0;
	});
}

function getPendingQty(row) {
	const qty = flt(row.qty);
	const deliveredQty = flt(row.delivered_qty);
	return Math.max(qty - Math.min(deliveredQty, qty), 0);
}

function flt(value) {
	if (frappe.utils && typeof frappe.utils.flt === "function") {
		return frappe.utils.flt(value || 0);
	}
	const parsed = parseFloat(value || 0);
	return Number.isNaN(parsed) ? 0 : parsed;
}

frappe.ui.form.on("Delivery Note", {
	setup(frm) {
		setupDeliveryNoteConsumableQuery(frm);
	},

	refresh(frm) {
		refreshDeliveryNoteFulfillmentTotals(frm);
		addDeliveryNoteConsumableButtons(frm);
	},

	manual_logistics_fee(frm) {
		refreshDeliveryNoteFulfillmentTotals(frm);
	},

	fulfillment_consumables_remove(frm) {
		refreshDeliveryNoteFulfillmentTotals(frm);
	}
});

frappe.ui.form.on("Delivery Note Fulfillment Consumable", {
	item_code(frm, cdt, cdn) {
		syncDeliveryNoteConsumableDefaults(frm, cdt, cdn);
	},

	qty(frm, cdt, cdn) {
		refreshDeliveryNoteConsumableAmount(frm, cdt, cdn);
	}
});

function setupDeliveryNoteConsumableQuery(frm) {
	const grid = frm.fields_dict.fulfillment_consumables && frm.fields_dict.fulfillment_consumables.grid;
	if (!grid) {
		return;
	}

	grid.get_field("item_code").get_query = function () {
		return {
			filters: {
				is_fulfillment_consumable: 1,
				disabled: 0
			}
		};
	};
}

function addDeliveryNoteConsumableButtons(frm) {
	if (frm.is_new() || frm.doc.docstatus === 2) {
		return;
	}

	if (frm.doc.fulfillment_consumable_stock_entry) {
		frm.add_custom_button("查看耗材出库", () => {
			frappe.set_route("Form", "Stock Entry", frm.doc.fulfillment_consumable_stock_entry);
		}, __("履约耗材"));
	}

	if (!(frm.doc.fulfillment_consumables || []).length) {
		return;
	}

	frm.add_custom_button("生成耗材出库", () => prepareDeliveryNoteConsumableStockEntry(frm), __("履约耗材"));
}

function prepareDeliveryNoteConsumableStockEntry(frm) {
	const invoke = () => frappe.call({
		method: "fashion_erp.fashion_stock.services.delivery_note_fulfillment_service.prepare_delivery_note_fulfillment_stock_entry",
		args: {
			delivery_note_name: frm.doc.name
		},
		freeze: true,
		freeze_message: __("生成耗材出库中...")
	}).then((response) => {
		const payload = response.message || {};
		if (payload.message) {
			frappe.show_alert({ message: payload.message, indicator: payload.ok === false ? "orange" : "green" }, 5);
		}
		return frm.reload_doc().then(() => {
			if (payload.stock_entry) {
				frappe.set_route("Form", "Stock Entry", payload.stock_entry);
			}
		});
	});

	if (frm.is_dirty()) {
		return frm.save().then(() => invoke());
	}

	return invoke();
}

function syncDeliveryNoteConsumableDefaults(frm, cdt, cdn) {
	const row = locals[cdt][cdn];
	if (!row.item_code) {
		return;
	}

	frappe.db.get_value(
		"Item",
		row.item_code,
		["item_name", "stock_uom", "supply_warehouse", "valuation_rate", "is_fulfillment_consumable"]
	).then((response) => {
		const item = response.message || {};
		if (!(item.is_fulfillment_consumable === 1 || item.is_fulfillment_consumable === "1")) {
			frappe.msgprint(__("只有包装耗材才能挂到出货单耗材明细。"));
			frappe.model.set_value(cdt, cdn, "item_code", "");
			return;
		}
		frappe.model.set_value(cdt, cdn, "item_name", item.item_name || "");
		frappe.model.set_value(cdt, cdn, "uom", item.stock_uom || "");
		if (!row.warehouse && item.supply_warehouse) {
			frappe.model.set_value(cdt, cdn, "warehouse", item.supply_warehouse);
		}
		frappe.model.set_value(cdt, cdn, "valuation_rate", flt(item.valuation_rate));
		if (!row.qty) {
			frappe.model.set_value(cdt, cdn, "qty", 1);
		}
		refreshDeliveryNoteConsumableAmount(frm, cdt, cdn);
	});
}

function refreshDeliveryNoteConsumableAmount(frm, cdt, cdn) {
	const row = locals[cdt][cdn];
	frappe.model.set_value(cdt, cdn, "estimated_amount", flt(row.qty) * flt(row.valuation_rate));
	refreshDeliveryNoteFulfillmentTotals(frm);
}

function refreshDeliveryNoteFulfillmentTotals(frm) {
	const rows = frm.doc.fulfillment_consumables || [];
	const qty = roundTo(rows.reduce((sum, row) => sum + flt(row.qty), 0), 6);
	const amount = roundTo(rows.reduce((sum, row) => sum + flt(row.estimated_amount), 0), 2);
	const total = roundTo(amount + flt(frm.doc.manual_logistics_fee), 2);
	frm.set_value("fulfillment_consumable_qty", qty);
	frm.set_value("fulfillment_consumable_amount", amount);
	frm.set_value("fulfillment_total_cost", total);
}

function roundTo(value, precision) {
	return Number(flt(value).toFixed(precision));
}

function flt(value) {
	if (frappe.utils && typeof frappe.utils.flt === "function") {
		return frappe.utils.flt(value || 0);
	}
	const parsed = parseFloat(value || 0);
	return Number.isNaN(parsed) ? 0 : parsed;
}

frappe.ui.form.on("Purchase Order Item", {
	item_code(frm, cdt, cdn) {
		applySupplyPurchaseDefaults(cdt, cdn);
	}
});

function applySupplyPurchaseDefaults(cdt, cdn) {
	const row = locals[cdt][cdn];
	if (!row.item_code) {
		return;
	}

	frappe.db.get_value(
		"Item",
		row.item_code,
		["item_usage_type", "supply_warehouse"]
	).then((response) => {
		const item = response.message || {};
		frappe.model.set_value(cdt, cdn, "item_usage_type", item.item_usage_type || "");
		if (!row.warehouse && item.supply_warehouse) {
			frappe.model.set_value(cdt, cdn, "warehouse", item.supply_warehouse);
		}
	});
}

frappe.ui.form.on("Purchase Receipt Item", {
	item_code(frm, cdt, cdn) {
		applySupplyReceiptDefaults(cdt, cdn);
	}
});

function applySupplyReceiptDefaults(cdt, cdn) {
	const row = locals[cdt][cdn];
	if (!row.item_code) {
		return;
	}

	frappe.db.get_value(
		"Item",
		row.item_code,
		["item_usage_type", "supply_warehouse"]
	).then((response) => {
		const item = response.message || {};
		frappe.model.set_value(cdt, cdn, "item_usage_type", item.item_usage_type || "");
		if (!row.warehouse && item.supply_warehouse) {
			frappe.model.set_value(cdt, cdn, "warehouse", item.supply_warehouse);
		}
	});
}

frappe.ui.form.on("Sales Order Item", {
	item_code(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.item_code) {
			return;
		}

		frappe.db.get_value(
			"Item",
			row.item_code,
			["style", "color_code", "color_name", "size_code", "size_name"]
		).then((response) => {
			const item = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", item.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", item.color_code || "");
			frappe.model.set_value(cdt, cdn, "color_name", item.color_name || "");
			frappe.model.set_value(cdt, cdn, "size_code", item.size_code || "");
			frappe.model.set_value(cdt, cdn, "size_name", item.size_name || "");
		});
	}
});

frappe.ui.form.on("Stock Entry Detail", {
	item_code(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.item_code) {
			return;
		}

		frappe.db.get_value(
			"Item",
			row.item_code,
			["style", "color_code", "size_code"]
		).then((response) => {
			const item = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", item.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", item.color_code || "");
			frappe.model.set_value(cdt, cdn, "size_code", item.size_code || "");
		});
	},

	production_ticket(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			row.production_ticket,
			["style", "color_code", "item_template"]
		).then((response) => {
			const ticket = response.message || {};
			frappe.model.set_value(cdt, cdn, "style", ticket.style || row.style || "");
			frappe.model.set_value(cdt, cdn, "color_code", ticket.color_code || row.color_code || "");
			if (!row.item_code && ticket.item_template) {
				frappe.model.set_value(cdt, cdn, "item_code", ticket.item_template);
			}
		});
	},

	return_disposition(frm, cdt, cdn) {
		const row = locals[cdt][cdn];
		if (!row.return_disposition) {
			return;
		}

		frappe.db.get_value(
			"Return Disposition",
			row.return_disposition,
			"target_inventory_status"
		).then((response) => {
			const disposition = response.message || {};
			if (disposition.target_inventory_status) {
				frappe.model.set_value(cdt, cdn, "inventory_status_to", disposition.target_inventory_status);
			}
		});
	}
});

frappe.ui.form.on("Stock Entry", {
	setup(frm) {
		const grid = frm.fields_dict.items && frm.fields_dict.items.grid;
		if (!grid) {
			return;
		}

		["inventory_status_from", "inventory_status_to"].forEach((fieldname) => {
			grid.get_field(fieldname).get_query = function () {
				return {
					filters: {
						enabled: 1
					}
				};
			};
		});

		["return_reason", "return_disposition"].forEach((fieldname) => {
			grid.get_field(fieldname).get_query = function () {
				return {
					filters: {
						enabled: 1
					}
				};
			};
		});
	}
});

frappe.ui.form.on("Work Order", {
	production_ticket(frm) {
		if (!frm.doc.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			frm.doc.production_ticket,
			["style", "color_code", "item_template", "bom_no", "qty"]
		).then((response) => {
			const ticket = response.message || {};
			if (ticket.style) {
				frm.set_value("style", ticket.style);
			}
			if (ticket.color_code) {
				frm.set_value("color_code", ticket.color_code);
			}
			if (!frm.doc.production_item && ticket.item_template) {
				frm.set_value("production_item", ticket.item_template);
			}
			if (!frm.doc.bom_no && ticket.bom_no) {
				frm.set_value("bom_no", ticket.bom_no);
			}
			if (!frm.doc.qty && ticket.qty) {
				frm.set_value("qty", ticket.qty);
			}
		});
	}
});

frappe.ui.form.on("BOM", {
	production_ticket(frm) {
		if (!frm.doc.production_ticket) {
			return;
		}

		frappe.db.get_value(
			"Production Ticket",
			frm.doc.production_ticket,
			["style", "color_code", "item_template"]
		).then((response) => {
			const ticket = response.message || {};
			if (ticket.style) {
				frm.set_value("style", ticket.style);
			}
			if (ticket.color_code) {
				frm.set_value("color_code", ticket.color_code);
			}
			if (!frm.doc.item && ticket.item_template) {
				frm.set_value("item", ticket.item_template);
			}
		});
	}
});
